16	def encode-varuint []: int -> binary {
17	    mut n = $in
18	    mut out = 0x[]
19	    while $n >= 128 {
20	        let byte = ($n mod 128) | bits or 128
21	        $out = ($out | bytes add --end ($byte | into binary | bytes at 0..0))
22	        $n = $n // 128
23	    }
24	    $out | bytes add --end ($n | into binary | bytes at 0..0)
25	}
