28	def parse-varuint [offset: int]: binary -> record<value: int, offset: int> {
29	    let buf = $in
30	    mut value = 0
31	    mut shift = 1
32	    mut pos = $offset
33	    loop {
34	        let b = $buf | bytes at $pos..($pos) | into int
35	        $value = $value + ($b mod 128) * $shift
36	        $pos = $pos + 1
37	        if ($b | bits and 0x80) == 0 { break }
38	        $shift = $shift * 128
39	    }
40	    {value: $value, offset: $pos}
41	}
